  ('elementary-7fec267e-moex-00301', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '有關選舉制度，依現行規定，下列敘述何者錯誤？', '["依現行制度，區域選出之立法委員仍為全國人民之代表，而非僅代表其選區之選民", "單一選區制有利於形成兩黨制", "比例代表制容易造成小黨林立，因此通常會設置得票門檻，未達門檻的政黨不分配席次", "我國立法委員選舉採複數選區制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
